import{_ as e,c as o,o as t,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Google Cloud 額度查詢 | opencode-mystatus","description":"學習 Google Cloud 額度查詢方法。查看 G3 Pro、G3 Image、G3 Flash 和 Claude 模型的剩餘額度和重置時間，管理多個 Antigravity 帳號。","frontmatter":{"title":"Google Cloud 額度查詢 | opencode-mystatus","sidebarTitle":"Google Cloud","subtitle":"Google Cloud 額度查詢","description":"學習 Google Cloud 額度查詢方法。查看 G3 Pro、G3 Image、G3 Flash 和 Claude 模型的剩餘額度和重置時間，管理多個 Antigravity 帳號。","tags":["Google Cloud","Antigravity","額度查詢"],"prerequisite":["start-quick-start","start-using-mystatus"],"order":4},"headers":[],"relativePath":"zh-tw/vbgate/opencode-mystatus/platforms/google-usage/index.md","filePath":"zh-tw/vbgate/opencode-mystatus/platforms/google-usage/index.md"}'),s={name:"zh-tw/vbgate/opencode-mystatus/platforms/google-usage/index.md"};function i(n,a,d,r,p,c){return t(),o("div",null,[...a[0]||(a[0]=[l(`<h1 id="google-cloud-額度查詢-g3-pro-image-flash-和-claude" tabindex="-1">Google Cloud 額度查詢：G3 Pro/Image/Flash 和 Claude <a class="header-anchor" href="#google-cloud-額度查詢-g3-pro-image-flash-和-claude" aria-label="Permalink to &quot;Google Cloud 額度查詢：G3 Pro/Image/Flash 和 Claude&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>查看 Google Cloud Antigravity 帳號的 4 個模型額度</li><li>理解每個模型的重置時間和剩餘百分比</li><li>管理多個 Google Cloud 帳號的額度使用</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>Google Cloud Antigravity 提供多個模型（G3 Pro、G3 Image、G3 Flash、Claude），每個模型有獨立的額度和重置時間。你需要：</p><ul><li>分別登入 Google Cloud 控制台查看每個模型的狀態</li><li>手動計算剩餘額度和重置時間</li><li>管理多個帳號時更加混亂</li></ul><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p>當你：</p><ul><li>想快速瞭解所有 Google Cloud 模型的剩餘額度</li><li>需要規劃在不同模型間的使用分配</li><li>有多個 Google Cloud 帳號需要統一管理</li></ul><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置檢查</p><ol><li><strong>已安裝 mystatus 外掛</strong>：參考 <a href="/docs/opencodedocs/zh-tw/vbgate/opencode-mystatus/start/quick-start/">快速開始</a></li><li><strong>已配置 Google Cloud 認證</strong>：需要先安裝 <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> 外掛完成 OAuth 認證</li><li><strong>認證檔案存在</strong>：<code>~/.config/opencode/antigravity-accounts.json</code> 至少包含一個帳號</li></ol></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Google Cloud Antigravity 透過 OAuth 機制認證，每個帳號有獨立的 Refresh Token。mystatus 外掛會：</p><ol><li>讀取 <code>antigravity-accounts.json</code> 取得所有已配置帳號</li><li>使用 Refresh Token 刷新 Access Token</li><li>呼叫 Google Cloud API 取得所有模型的額度</li><li>按帳號分組顯示 4 個模型的額度和重置時間</li></ol><h2 id="google-cloud-支援的模型" tabindex="-1">Google Cloud 支援的模型 <a class="header-anchor" href="#google-cloud-支援的模型" aria-label="Permalink to &quot;Google Cloud 支援的模型&quot;">​</a></h2><p>mystatus 顯示以下 4 個模型的額度：</p><table tabindex="0"><thead><tr><th>顯示名稱</th><th>模型 Key（主/備）</th><th>說明</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code> / <code>gemini-3-pro-low</code></td><td>Gemini 3 Pro 高效能版本</td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>Gemini 3 Pro 影像生成</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>Gemini 3 Flash 快速版本</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code> / <code>claude-opus-4-5</code></td><td>Claude Opus 4.5 模型</td></tr></tbody></table><p><strong>主 Key 和備 Key 機制</strong>：</p><ul><li>API 回應中可能只返回主 key 或備 key 的資料</li><li>mystatus 會自動嘗試取得任一 key 的額度</li><li>例如：如果 <code>gemini-3-pro-high</code> 沒有資料，會嘗試 <code>gemini-3-pro-low</code></li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-執行查詢指令" tabindex="-1">第 1 步：執行查詢指令 <a class="header-anchor" href="#第-1-步-執行查詢指令" aria-label="Permalink to &quot;第 1 步：執行查詢指令&quot;">​</a></h3><p><strong>為什麼</strong> 快速取得所有 Google Cloud 帳號的額度資訊</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><p><strong>你應該看到</strong> 包含所有已配置平台的額度資訊，其中 Google Cloud 部分會顯示類似以下內容：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Google Cloud Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Flash   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>Claude     2d 9h      ░░░░░░░░░░░░░░░░░░░░ 0%</span></span></code></pre></div><h3 id="第-2-步-理解輸出格式" tabindex="-1">第 2 步：理解輸出格式 <a class="header-anchor" href="#第-2-步-理解輸出格式" aria-label="Permalink to &quot;第 2 步：理解輸出格式&quot;">​</a></h3><p><strong>為什麼</strong> 快速定位關鍵資訊：剩餘額度和重置時間</p><p>每行格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[模型名] [重置時間] [進度條] [剩餘百分比]</span></span></code></pre></div><p><strong>欄位說明</strong>：</p><ul><li><strong>模型名</strong>：G3 Pro、G3 Image、G3 Flash、Claude</li><li><strong>重置時間</strong>：距離下次額度的剩餘時間（如 <code>4h 59m</code>、<code>2d 9h</code>）</li><li><strong>進度條</strong>：可視化顯示剩餘百分比</li><li><strong>剩餘百分比</strong>：0-100 的數值</li></ul><p><strong>你應該看到</strong> 每個模型一行，清晰顯示額度和重置時間</p><h3 id="第-3-步-查看多帳號情況" tabindex="-1">第 3 步：查看多帳號情況 <a class="header-anchor" href="#第-3-步-查看多帳號情況" aria-label="Permalink to &quot;第 3 步：查看多帳號情況&quot;">​</a></h3><p><strong>為什麼</strong> 如果你有多個 Google Cloud 帳號，會分別顯示</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### another@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     2h 30m     ████████████░░░░░░░░░ 75%</span></span>
<span class="line"><span>G3 Image   2h 30m     ████████████░░░░░░░░░ 75%</span></span></code></pre></div><p><strong>你應該看到</strong> 每個帳號單獨一個區塊，包含該帳號的 4 個模型額度</p><h3 id="第-4-步-檢查額度警告" tabindex="-1">第 4 步：檢查額度警告 <a class="header-anchor" href="#第-4-步-檢查額度警告" aria-label="Permalink to &quot;第 4 步：檢查額度警告&quot;">​</a></h3><p><strong>為什麼</strong> 避免超額使用導致服務中斷</p><p>如果任一模型的使用率超過 80%，會顯示警告提示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     1h 30m     ████░░░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span>G3 Image   1h 30m     ████░░░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠️ 使用率已達到或超過 80%</span></span></code></pre></div><p><strong>你應該看到</strong> 警告提示出現在對應帳號的模型列表下方</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><p>完成以下檢查，確保你做對了：</p><ul><li>[ ] 執行 <code>/mystatus</code> 後能看到 Google Cloud 額度資訊</li><li>[ ] 能理解 4 個模型的名稱和重置時間</li><li>[ ] 能識別進度條和剩餘百分比</li><li>[ ] 如果有多帳號，能看到所有帳號的額度</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="問題-1-看不到-google-cloud-額度" tabindex="-1">問題 1：看不到 Google Cloud 額度 <a class="header-anchor" href="#問題-1-看不到-google-cloud-額度" aria-label="Permalink to &quot;問題 1：看不到 Google Cloud 額度&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>未安裝 opencode-antigravity-auth 外掛</li><li>未完成 Google OAuth 認證</li><li><code>antigravity-accounts.json</code> 檔案不存在或為空</li></ul><p><strong>解決方案</strong>：</p><ol><li>安裝 opencode-antigravity-auth 外掛</li><li>按照 GitHub 儲存庫的說明完成認證</li><li>重新執行 <code>/mystatus</code></li></ol><h3 id="問題-2-某個帳號顯示錯誤" tabindex="-1">問題 2：某個帳號顯示錯誤 <a class="header-anchor" href="#問題-2-某個帳號顯示錯誤" aria-label="Permalink to &quot;問題 2：某個帳號顯示錯誤&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>Refresh Token 過期</li><li>projectId 缺失</li></ul><p><strong>錯誤範例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user@gmail.com: No project ID found</span></span></code></pre></div><p><strong>解決方案</strong>：</p><ol><li>重新使用 opencode-antigravity-auth 外掛認證該帳號</li><li>確保在認證過程中正確設定了專案 ID</li></ol><h3 id="問題-3-模型顯示-或重置時間異常" tabindex="-1">問題 3：模型顯示&quot;-&quot;或重置時間異常 <a class="header-anchor" href="#問題-3-模型顯示-或重置時間異常" aria-label="Permalink to &quot;問題 3：模型顯示&quot;-&quot;或重置時間異常&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>API 返回的 resetTime 欄位缺失或格式異常</li><li>該模型暫無額度資訊</li></ul><p><strong>解決方案</strong>：</p><ul><li>這是正常的，mystatus 會顯示&quot;-&quot;表示資料不可用</li><li>如所有模型都顯示&quot;-&quot;，檢查網路連線或 Google Cloud API 狀態</li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>Google Cloud Antigravity 支援 4 個模型：G3 Pro、G3 Image、G3 Flash、Claude</li><li>每個模型有獨立的額度和重置時間</li><li>支援多帳號管理，每個帳號單獨顯示</li><li>使用率超過 80% 時會顯示警告提示</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../../advanced/google-setup/">Google Cloud 進階設定：多帳號和模型管理</a></strong>。</p><p>你會學到：</p><ul><li>如何新增和管理多個 Google Cloud 帳號</li><li>理解 4 個模型的映射關係</li><li>projectId 和 managedProjectId 的區別</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>模型設定</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L69-L78" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>帳號查詢邏輯</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L304-L370" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>304-370</td></tr><tr><td>Token 重新整理</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L162-L184" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>162-184</td></tr><tr><td>額度提取</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L132-L157" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>132-157</td></tr><tr><td>格式化輸出</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L265-L294" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>265-294</td></tr><tr><td>類型定義</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L78-L94" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>78-94</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>GOOGLE_QUOTA_API_URL = &quot;https://cloudcode-pa.googleapis.com/v1internal:fetchAvailableModels&quot;</code>：Google Cloud 額度查詢 API</li><li><code>GOOGLE_TOKEN_REFRESH_URL = &quot;https://oauth2.googleapis.com/token&quot;</code>：OAuth Token 重新整理 API</li><li><code>USER_AGENT = &quot;antigravity/1.11.9 windows/amd64&quot;</code>：API 請求 User-Agent</li></ul><p><strong>關鍵函數</strong>：</p><ul><li><code>queryGoogleUsage()</code>：查詢所有 Antigravity 帳號的額度</li><li><code>fetchAccountQuota()</code>：查詢單個帳號的額度</li><li><code>extractModelQuotas()</code>：從 API 回應中提取 4 個模型的額度</li><li><code>formatAccountQuota()</code>：格式化單個帳號的額度顯示</li></ul><p><strong>模型映射規則</strong>：</p><ul><li>G3 Pro 支援 <code>gemini-3-pro-high</code> 和 <code>gemini-3-pro-low</code>，優先使用主 key</li><li>Claude 支援 <code>claude-opus-4-5-thinking</code> 和 <code>claude-opus-4-5</code>，優先使用主 key</li><li>G3 Image 和 G3 Flash 只有一個 key</li></ul></details>`,69)])])}const h=e(s,[["render",i]]);export{u as __pageData,h as default};
